{
  "query": "mutation Signup($input: SignupInput!) {\n  signup(input: $input) {\n    success\n    message\n    token\n    user { _id username email }\n  }\n}",
  "variables": {
    "input": {
      "username": "oleg_demo",
      "email": "oleg_demo@example.com",
      "password": "Password123"
    }
  }
}

{
  "query": "query Login($input: LoginInput!) {\n  login(input: $input) {\n    success\n    message\n    token\n  }\n}",
  "variables": {
    "input": {
      "usernameOrEmail": "oleg1atest.com",
      "password": "Password123"
    }
  }
}

{
  "query": "query {
  getAllEmployees {
    success
    message
    employees {
      _id
      first_name
      last_name
      email
      gender
      designation
      salary
      date_of_joining
      department
      employee_photo
      created_at
      updated_at
    }
  }
}",
  "variables": {}
}

{
  "query": "mutation AddEmployee($input: EmployeeInput!) {\n  addEmployee(input: $input) {\n    success\n    message\n    employee {\n      _id\n      first_name\n      last_name\n      department\n      designation\n      employee_photo\n    }\n  }\n}",
  "variables": {
    "input": {
      "first_name": "John",
      "last_name": "Doe",
      "email": "john.doe1@company.com",
      "gender": "Male",
      "designation": "Developer",
      "salary": 3500,
      "date_of_joining": "2024-01-15T00:00:00.000Z",
      "department": "IT",
      "employee_photo": "https://picsum.photos/seed/emp1/400"
    }
  }
}

{
  "query": "query SearchByEid($eid: ID!) {
  searchEmployeeByEid(eid: $eid) {
    success
    message
    employee {
      _id
      first_name
      last_name
      email
      gender
      designation
      salary
      date_of_joining
      department
      employee_photo
    }
  }
}",
  "variables": {
    "eid": "PUT_EMPLOYEE_ID_HERE"
  }
}

{
  "query": "mutation UpdateByEid($eid: ID!, $input: EmployeeUpdateInput!) {
  updateEmployeeByEid(eid: $eid, input: $input) {
    success
    message
    employee {
      _id
      first_name
      last_name
      salary
      designation
      department
      employee_photo
    }
  }
}",
  "variables": {
    "eid": "PUT_EMPLOYEE_ID_HERE",
    "input": {
      "salary": 5000
    }
  }
}

{
  "query": "query SearchByDesignationOrDepartment($designation: String, $department: String) {
  searchEmployeesByDesignationOrDepartment(designation: $designation, department: $department) {
    success
    message
    employees {
      _id
      first_name
      last_name
      designation
      department
      employee_photo
    }
  }
}",
  "variables": {
    "designation": "Developer",
    "department": null
  }
}
